#include "kernel_operator.h"

constexpr float NEG_INF = -FLT_MAX;
constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00343Custom {
public:
    __aicore__ inline KernelCa6k00343Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t N, uint32_t C, uint32_t L,
                                uint32_t outputSize, uint32_t tileLength) {
        N_ = N;
        C_ = C;
        L_ = L;
        outputSize_ = outputSize;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, N_ * C_ * L_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, N_ * C_ * outputSize_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, 1, outputSize_ * sizeof(float)); // output max buffer
    }

    __aicore__ inline void Process() {
        if (N_ == 0 || C_ == 0 || L_ == 0 || outputSize_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t totalSlices = N_ * C_;
        uint32_t slicesPerBlock = (totalSlices + blockNum - 1) / blockNum;
        uint32_t startSlice = blockIdx * slicesPerBlock;
        uint32_t endSlice = startSlice + slicesPerBlock;
        if (endSlice > totalSlices) endSlice = totalSlices;

        for (uint32_t sliceIdx = startSlice; sliceIdx < endSlice; ++sliceIdx) {
            uint32_t n = sliceIdx / C_;
            uint32_t c = sliceIdx % C_;
            ProcessSlice(n, c);
        }
    }

private:
    __aicore__ inline void ProcessSlice(uint32_t n, uint32_t c) {
        uint32_t sliceOffset = (n * C_ + c) * L_;
        uint32_t outOffset = (n * C_ + c) * outputSize_;

        // Allocate local tensor for output max array
        AscendC::LocalTensor<float> maxLocal = outQueueY_.AllocTensor<float>();

        // Initialize max array to NEG_INF
        for (uint32_t j = 0; j < outputSize_; ++j) {
            maxLocal(j) = NEG_INF;
        }

        // Loop over input tiles
        uint32_t processed = 0;
        while (processed < L_) {
            uint32_t curLen = L_ - processed;
            if (curLen > tileLen_) curLen = tileLen_;

            // Allocate and copy next tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[sliceOffset + processed], curLen);

            // Process each element in the tile
            for (uint32_t i = 0; i < curLen; ++i) {
                float val = xLocal(i);
                uint32_t bin = ((processed + i) * outputSize_) / L_;
                if (val > maxLocal(bin)) {
                    maxLocal(bin) = val;
                }
            }

            inQueueX_.FreeTensor(xLocal);
            processed += curLen;
        }

        // Write output max array to global memory
        AscendC::DataCopy(yGm_[outOffset], maxLocal, outputSize_);
        outQueueY_.FreeTensor(maxLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueY_; // single buffer for output max

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_ {0};
    uint32_t C_ {0};
    uint32_t L_ {0};
    uint32_t outputSize_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00343_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00343Custom op;
    op.Init(x, y, tiling_data.N, tiling_data.C, tiling_data.L, tiling_data.outputSize, tiling_data.tileLength);
    op.Process();
}
